import { OrderDetailDataAttributeDto } from '../api';
import { PointsTransaction } from '../models';
import { UIElement } from '../models/ui.model';

type Payload = {
  elements: Required<PointsTransaction['details']['elements']>;
};

type AttributeMap = Record<string, string>;

function buildAttributeMap(dto: OrderDetailDataAttributeDto[]): AttributeMap {
  const map: AttributeMap = {};
  for (const attr of dto) {
    map[attr.key] = String(attr.values);
  }
  return map;
}

function buildTagValue(attrs: AttributeMap): string {
  const marca = attrs['marca veiculo'] ?? '';
  const modelo = attrs['modelo veiculo'] ?? '';
  const placa = attrs['placa veiculo'] ?? '';

  const vehicle = [marca, modelo].filter(Boolean).join(' ');
  if (!vehicle && !placa) return '';

  return placa ? `${vehicle} - ${placa}` : vehicle;
}

function formatDollarValue(raw: string): string {
  return `US$ ${raw}`;
}

export function mapOrderDetailAttributes(
  dto: OrderDetailDataAttributeDto[],
): Payload {
  const attrs = buildAttributeMap(dto);
  const elements: UIElement[] = [];

  const valorDolar = attrs['valor dolar'];
  if (valorDolar) {
    elements.push({
      type: 'KeyValueRow',
      props: {
        label: 'Valor em dólar',
        value: formatDollarValue(valorDolar),
        showDivider: true,
      },
    });
  }

  const tagValue = buildTagValue(attrs);
  if (tagValue) {
    elements.push({
      type: 'KeyValueRow',
      props: {
        label: 'Tag',
        value: tagValue,
        showDivider: true,
      },
    });
  }

  const razaoUsoTag = attrs['razao uso tag'];
  if (razaoUsoTag) {
    elements.push({
      type: 'KeyValueRow',
      props: {
        label: 'Tipo de compra',
        value: razaoUsoTag,
        showDivider: true,
      },
    });
  }

  return { elements };
}

